indi'=>'Hindi','India'=>'India','Pakistan'=>'Pakistan','Hungarian'=>'Hungaria','Hungary'=>'Hongaria','Indonesian'=>'Bahasa Indonesia','Indonesia'=>'Indonesia','Italian'=>'Italia','Italy'=>'Italia','Japanese'=>'Jepang','Japan'=>'Jepang','Korean'=>'Korea','South Korea'=>'Korea Selatan','North Korea'=>'Korea Utara','Polish'=>'Polandia','Poland'=>'Polandia','Portuguese'=>'Portugis','Portugal'=>'Portugal','Brazil'=>'Brazil','Mozambique'=>'Mozambik','Angola'=>'Angola','Russian'=>'Rusia','Russia'=>'Rusia','Kazakhstan'=>'Kazakhstan','Belarus'=>'Belarus','Kyrgyzstan'=>'Kirgistan','Tajikistan'=>'Tajikistan','Spanish'=>'Spanyol','Spain'=>'Spanyol','Mexico'=>'Meksiko','Argentina'=>'Argentina','Colombia'=>'Kolombia','Peru'=>'Peru','Ecuador'=>'Ekuador','Bolivia'=>'Bolivia','Chile'=>'Chili','Equatorial Guinea'=>'Guinea ekuator','Guatemala'=>'Guatemala','Cuba'=>'Kuba','Dominican Republic'=>'Republik Dominika','Honduras'=>'Honduras','Paraguay'=>'Paraguay','El Salvador'=>'El Salvador','Nicaragua'=>'Nicaragua','Costa Rica'=>'Kosta Rika','Panama'=>'Panama','Uruguay'=>'Uruguay','Swedish'=>'Swedia','Sweden'=>'Swedia','Turkish'=>'Turki','Turkey'=>'Turki','Ukrainian'=>'Ukraina','Ukraine'=>'Ukraina','Vietnamese'=>'Vietnam','Vietnam'=>'Vietnam','Bottom right'=>'Kanan bawah','Bottom center'=>'Bagian tengah bawah','Bottom left'=>'Kiri bawah','None'=>'Nihil','Light - Double - Smooth'=>'Ringan - Ganda - Halus','Light - Double - Square'=>'Cahaya - Ganda - Persegi','Light - Simple - Smooth'=>'Ringan - Sederhana - Halus','Light - Simple - Square'=>'Cahaya - Sederhana - Persegi','Grey - Double - Smooth'=>'Abu-abu - Ganda - Halus','Grey - Double - Square'=>'Abu-abu - Ganda - Persegi','Grey - Simple - Smooth'=>'Abu-abu - Sederhana - Halus','Grey - Simple - Square'=>'Abu-abu - Sederhana - Persegi','Dark - Double - Smooth'=>'Gelap - Ganda - Halus','Dark - Double - Square'=>'Gelap - Ganda - Persegi','Dark - Simple - Smooth'=>'Gelap - Sederhana - Halus','Dark - Simple - Square'=>'Gelap - Sederhana - Kotak','Blur Black - Double - Smooth'=>'Buram Hitam - Ganda - Halus','Blur Black - Double - Square'=>'Buram Hitam - Ganda - Persegi','Blur Black - Simple - Smooth'=>'Buram Hitam - Sederhana - Halus','Blur Black - Simple - Square'=>'Buram Hitam - Sederhana - Persegi','Blur White - Double - Smooth'=>'Buram Putih - Ganda - Halus','Blur White - Double - Square'=>'Buram Putih - Ganda - Persegi','Blur White - Simple - Smooth'=>'Blur Putih - Sederhana - Halus','Blur White - Simple - Square'=>'Putih Buram - Sederhana - Persegi','Inline list'=>'Daftar sebaris','Block'=>'Blok','Dropdown'=>'Dropdown','Original name'=>'Nama asli','Translated name'=>'Nama yang diterjemahkan','Language ID'=>'ID Bahasa','No display'=>'Tidak ada tampilan','Circle'=>'Lingkaran','Rectangular'=>'Persegi panjang','Wave'=>'Gelombang','Display'=>'Tampilan','List without current language'=>'Daftar tanpa bahasa saat ini','List without active class'=>'Daftar tanpa kelas aktif','List with active class'=>'Daftar dengan kelas aktif','Sub-list'=>'Sub-daftar','wpLingua'=>'wpLingua','This URL is excluded from translation'=>'URL ini dikecualikan dari terjemahan','Return on page'=>'Kembali ke halaman','Visual editor'=>'Editor visual','All translations on page'=>'Semua terjemahan pada halaman','Edit the page slug'=>'Mengedit slug halaman','Translations'=>'Terjemahan','Edit translations'=>'Edit terjemahan','You are about to leave the page without saving your changes. They will be lost if you continue. Would you like to leave the page anyway?'=>'Anda akan meninggalkan halaman tanpa menyimpan perubahan Anda. Perubahan tersebut akan hilang jika Anda melanjutkan. Apakah Anda tetap ingin meninggalkan halaman?','wpLingua - Dictionary rules'=>'wpLingua - Aturan kamus','Debug'=>'Awakutu','Dictionary entries'=>'Entri kamus','Translation rules by dictionary: '=>'Aturan penerjemahan berdasarkan kamus: ','The dictionary allows you to define translation rules that apply when generating machine translations. You can specify words or sets of words that should never be translated, or define how they should be translated for each language.'=>'Kamus memungkinkan Anda untuk menentukan aturan penerjemahan yang berlaku saat menghasilkan terjemahan mesin. Anda dapat menentukan kata atau kumpulan kata yang tidak boleh diterjemahkan, atau menentukan bagaimana kata tersebut harus diterjemahkan untuk setiap bahasa.','Add a dictionary entry'=>'Menambahkan entri kamus','Add an entry'=>'Menambahkan entri','Edit the entry'=>'Mengedit entri','All dictionary entries: '=>'Semua entri kamus: ','Rule N°'=>'Aturan No','Edit'=>'Edit','Remove'=>'Hapus','Always translate: '=>'Selalu terjemahkan: ',' - By: '=>' - Oleh: ','Never translate: '=>'Jangan pernah menerjemahkan: ','Source text: '=>'Teks sumber: ','Never translate'=>'Jangan pernah menerjemahkan',' - Always translate by: '=>' - Selalu terjemahkan oleh: ','Cancel'=>'Batal','Save new entry'=>'Menyimpan entri baru','Save edited entry'=>'Menyimpan entri yang telah diedit','wpLingua - Exclusion rules'=>'wpLingua - Aturan pengecualian','Exclude URL'=>'Kecualikan URL','Exclude URL from translation: '=>'Kecualikan URL dari terjemahan: ','You can exclude from translations pages you wish to offer only in the website\'s original language. To do this, list the REGEXs that match the URL to be excluded, one per line. Examples: '=>'Anda dapat mengecualikan halaman terjemahan yang ingin Anda tawarkan hanya dalam bahasa asli situs web. Untuk melakukan ini, buat daftar REGEX yang sesuai dengan URL yang akan dikecualikan, satu per baris. Contoh: ','Exclude URL "/my-page/"'=>'Kecualikan URL "/halaman-saya/"','Exclude URL starting with "/my-page/"'=>'Kecualikan URL yang dimulai dengan "/halaman-saya/"','Exclude URL ending with "/my-page/"'=>'Kecualikan URL yang diakhiri dengan "/halaman-saya/"','Exclude URL containing "/my-page/"'=>'Kecualikan URL yang mengandung "/halaman-saya/"','Exclude elements'=>'Mengecualikan elemen','Exclude HTML elements: '=>'Mengecualikan elemen HTML: ','You can leave some elements of your web pages untranslated. To do this, list below the CSS selectors for the elements to be excluded, one per line. Examples: '=>'Anda dapat membiarkan beberapa elemen halaman web Anda tidak diterjemahkan. Untuk melakukan hal ini, cantumkan di bawah pemilih CSS untuk elemen yang akan dikecualikan, satu per baris. Contoh: ','Exclude elements by ID attribute'=>'Mengecualikan elemen berdasarkan atribut ID','Exclude elements by class attribute'=>'Mengecualikan elemen berdasarkan atribut kelas','Exclude elements by CSS selector'=>'Mengecualikan elemen dengan pemilih CSS','Save'=>'Simpan','wpLingua - Links & Medias'=>'wpLingua - Tautan & Media','Links & medias'=>'Tautan & media','Links and medias translations rules: '=>'Aturan penerjemahan tautan dan media: ','Translation rules on links and media allow different images to be displayed or link URLs to be changed according to the current language. These rules apply to elements such as: link target URLs, image source URLs, iframe source URLs, URLs in intercepted JSONs...'=>'Aturan penerjemahan pada tautan dan media memungkinkan gambar yang berbeda ditampilkan atau URL tautan diubah sesuai dengan bahasa yang digunakan. Aturan ini berlaku untuk elemen-elemen seperti: URL target tautan, URL sumber gambar, URL sumber iframe, URL dalam JSON yang disadap...','Add a rule'=>'Menambahkan aturan','All links and medias rules: '=>'Semua aturan tautan dan media: ','Mode: '=>'Mode: ','Exactly equal'=>'Persis sama','Partially equal'=>'Sebagian sama','Regex'=>'Regex','Error'=>'Kesalahan','Original: '=>'Asli: ','Original URL: '=>'URL asli: ','REGEX'=>'REGEX',' - URL: '=>' - URL: ','Message: '=>'Pesan: ','An error occurred with API key.'=>'Terjadi kesalahan pada kunci API.','Invalid API key.'=>'Kunci API tidak valid.','An error occurred while creating the API key.'=>'Terjadi kesalahan saat membuat kunci API.','wpLingua - Register API key'=>'wpLingua - Daftarkan kunci API','API key created'=>'Kunci API dibuat','API key created and sent by email'=>'Kunci API dibuat dan dikirim melalui email','The API key has been correctly created and sent to the following e-mail address: '=>'Kunci API telah dibuat dengan benar dan dikirim ke alamat email berikut: ','Go to your mailbox and copy the API key sent to you (don\'t forget to check the spam section of your mailbox). Then paste it in the section below, and click "Set API key" to make your website multilingual.'=>'Buka kotak surat Anda dan salin kunci API yang dikirimkan kepada Anda (jangan lupa untuk memeriksa bagian spam pada kotak surat Anda). Kemudian tempelkan pada bagian di bawah ini, dan klik "Set API key" untuk menjadikan situs web Anda multibahasa.','Set API Key'=>'Mengatur Kunci API','Get API key'=>'Dapatkan kunci API','Start with wpLingua'=>'Mulai dengan wpLingua','You are just a few clicks away from making your website multilingual!'=>'Anda hanya perlu beberapa klik saja untuk membuat situs web Anda menjadi multibahasa!','For wpLingua to work, an API key is required so that your website has access to the automatic translation service. On this page you can enter your API key if you already have one, or create one for free.'=>'Agar wpLingua dapat berfungsi, diperlukan kunci API agar situs web Anda memiliki akses ke layanan penerjemahan otomatis. Di halaman ini Anda dapat memasukkan kunci API jika Anda sudah memilikinya, atau membuatnya secara gratis.','An <strong>instantly multilingual website</strong> thanks to automatic text detection and translation. Easy to use, no knowledge required.'=>'<strong>Situs web multibahasa secara instan</strong> berkat deteksi dan terjemahan teks otomatis. Mudah digunakan, tidak perlu pengetahuan khusus.','<strong>SEO friendly</strong> to allow search engines to index translated pages. Open up your website and your business to the whole world.'=>'<strong>Ramah SEO</strong> agar mesin pencari dapat mengindeks halaman yang diterjemahkan. Buka situs web dan bisnis Anda ke seluruh dunia.','All <strong>translations are editable</strong>. Discover the visual editor and edit translations simply by clicking on them. With a fully customizable language switcher.'=>'Semua <strong>terjemahan dapat diedit.</strong> Temukan editor visual dan edit terjemahan hanya dengan mengekliknya. Dengan pengalih bahasa yang dapat disesuaikan sepenuhnya.','One <strong>free and unlimited</strong> language for personal blogs and non-commercial websites. And many more features!'=>'Satu bahasa <strong>gratis dan tak terbatas</strong> untuk blog pribadi dan situs web non-komersial. Dan masih banyak lagi fitur lainnya!','Set API key'=>'Tetapkan kunci API','Advanced API features'=>'Fitur API tingkat lanjut','Important Notice'=>'Pemberitahuan Penting','Website incompatible with string translation'=>'Situs web tidak kompatibel dengan terjemahan teks','Your website contains a large amount of content, which exceeds the limits of the string translation method used by wpLingua.'=>'Situs web Anda mengandung sejumlah besar konten, yang melebihi batas metode terjemahan string yang digunakan oleh wpLingua.','Why the website is incompatible'=>'Mengapa situs web tidak kompatibel','wpLingua works by identifying and translating each string of characters individually. On a large website, this method generates a very large number of database entries, causing overload and slowdowns.'=>'wpLingua bekerja dengan mengidentifikasi dan menerjemahkan setiap rangkaian karakter secara individual. Pada situs web yang besar, metode ini menghasilkan jumlah entri database yang sangat besar, menyebabkan kelebihan beban dan perlambatan.','Recommended solution'=>'Solusi yang direkomendasikan','To make large websites multilingual, we recommend using a translation plugin based on content duplication, such as Polylang or WPML. These solutions are specifically designed to efficiently manage large websites.'=>'Untuk membuat situs web besar menjadi multibahasa, kami merekomendasikan penggunaan plugin terjemahan yang berbasis duplikasi konten, seperti Polylang atau WPML. Solusi-solusi ini dirancang khusus untuk mengelola situs web besar dengan efisien.','Set the wpLingua API key: '=>'Tetapkan kunci API wpLingua: ','If you already have an API key, enter it below. If you\'ve forgotten your website\'s API key, visit'=>'Jika Anda sudah memiliki kunci API, masukkan di bawah ini. Jika Anda lupa kunci API situs web Anda, kunjungi','the API key retrieval page'=>'halaman pengambilan kunci API','Click to expand'=>'Klik untuk memperluas','A wpLingua API key consists of 42 characters (uppercase, lowercase and numbers). It is emailed to you when you request it using the form provided when you install the plugin. You must keep this key secret and only communicate it to wplingua.com services.'=>'Kunci API wpLingua terdiri dari 42 karakter (huruf besar, huruf kecil, dan angka). Kunci ini akan dikirimkan melalui email kepada Anda saat Anda memintanya menggunakan formulir yang disediakan saat Anda menginstal plugin. Anda harus merahasiakan kunci ini dan hanya mengomunikasikannya ke layanan wplingua.com.','Register wpLingua API key: '=>'Daftarkan kunci API wpLingua: ','Claim a wpLingua API key and make your website multilingual in a minute! For a personal blog or a non-commercial website, get one unlimited free language.'=>'Klaim kunci API wpLingua dan jadikan situs web Anda multibahasa dalam satu menit! Untuk blog pribadi atau situs web non-komersial, dapatkan satu bahasa gratis tanpa batas.','Email address: '=>'Alamat email: ','The email address is detected and pre-filled. This is the administrative email address entered in the Settings ➔ General tab. You can use another email address used to receive your API key.'=>'Alamat email terdeteksi dan sudah diisi sebelumnya. Ini adalah alamat email administratif yang dimasukkan di tab Pengaturan ➔ Umum. Anda dapat menggunakan alamat email lain yang digunakan untuk menerima kunci API.','Website URL: '=>'URL situs web: ','This is the URL of your website, it is detected and pre-filled automatically. Please check it and only enter the address of your production website (no test website or development environment).'=>'Ini adalah URL situs web Anda, terdeteksi dan terisi secara otomatis. Silakan periksa dan masukkan alamat situs web produksi Anda saja (jangan masukkan situs web uji coba atau lingkungan pengembangan).','Website language: '=>'Bahasa situs web: ','This is the language of your website, defined by the associated API key. Make sure your website language is also correctly set in WordPress options (Settings ➔ General ➔ Website Language).'=>'Ini adalah bahasa situs web Anda, yang ditentukan oleh kunci API terkait. Pastikan bahasa situs web Anda juga diatur dengan benar dalam opsi WordPress (Pengaturan ➔ Umum ➔ Bahasa Situs Web).','Target language: '=>'Bahasa target: ','This is the language you want to translate your website into. Be careful not to make a mistake because you will not be able to change the language afterwards.'=>'Ini adalah bahasa yang Anda inginkan untuk menerjemahkan situs web Anda. Berhati-hatilah agar tidak membuat kesalahan karena Anda tidak dapat mengubah bahasa setelahnya.','I have read and accept the'=>'Saya telah membaca dan menerima','API terms of use'=>'Ketentuan penggunaan API','Website Locale: '=>'Lokasi Situs Web: ','Get more target languages and advanced features: '=>'Dapatkan lebih banyak bahasa target dan fitur-fitur canggih: ','To translate your website into more languages and access advanced features, visit wpLingua website.'=>'Untuk menerjemahkan situs web Anda ke dalam lebih banyak bahasa dan mengakses fitur-fitur canggih, kunjungi situs web wpLingua.','Use wpLingua on commercial website'=>'Gunakan wpLingua di situs web komersial','Allow search from all languages'=>'Izinkan pencarian dari semua bahasa','Get more target languages'=>'Dapatkan lebih banyak bahasa target','Visit wpLingua website'=>'Kunjungi situs web wpLingua','wpLingua - General settings'=>'wpLingua - Pengaturan umum','Website language'=>'Bahasa situs web','Translated languages'=>'Bahasa yang diterjemahkan','Features'=>'Fitur','API Key'=>'API Key','Your website is being translated and will be ready soon.'=>'Situs web Anda sedang diterjemahkan dan akan segera siap.','In just a few seconds, your website will be multilingual, and search engines will be able to index these new pages. wpLingua detects all the texts on your pages and offers you a first automatically generated translation. All translations are editable: open the visual editor from the administration bar and edit them simply by clicking on the texts on your website.'=>'Hanya dalam beberapa detik, situs web Anda akan menjadi multibahasa, dan mesin pencari akan dapat mengindeks halaman-halaman baru ini. wpLingua mendeteksi semua teks di halaman Anda dan menawarkan terjemahan pertama yang dibuat secara otomatis. Semua terjemahan dapat diedit: buka editor visual dari bilah administrasi dan edit hanya dengan mengeklik teks di situs web Anda.','Translation progress: '=>'Kemajuan terjemahan: ','Your website is now multilingual!'=>'Situs web Anda kini tersedia dalam berbagai bahasa!','You can start visiting the translated version.'=>'Anda dapat mulai mengakses versi terjemahannya.','The first time a translated page is loaded, the translations are automatically generated and saved in the database. This may take some time (on first generation only) depending on the size of your content. This is why we advise you to browse your entire website for the first time in order to generate all the multilingual versions.'=>'Saat pertama kali halaman yang diterjemahkan dimuat, terjemahan secara otomatis dibuat dan disimpan dalam database. Hal ini mungkin memerlukan waktu (hanya pada generasi pertama), tergantung pada ukuran konten Anda. Inilah sebabnya mengapa kami menyarankan Anda untuk menelusuri seluruh situs web Anda untuk pertama kalinya agar dapat menghasilkan semua versi multibahasa.','All translations are editable: open the visual editor from the administration bar and edit them simply by clicking on the texts on your website.'=>'Semua terjemahan dapat diedit: buka editor visual dari bilah administrasi dan edit hanya dengan mengeklik teks pada situs web Anda.','Visit your multilingual website'=>'Kunjungi situs web multibahasa Anda','Original website language: '=>'Bahasa asli situs web: ','Please choose an option'=>'Silakan pilih salah satu opsi','Original website language, defined by API key: '=>'Bahasa situs web asli, ditentukan oleh kunci API: ','If you have mistakenly selected the wrong language, you can delete the API key in the site options below and request a new API key.'=>'Jika Anda salah memilih bahasa, Anda dapat menghapus kunci API pada opsi situs di bawah ini dan meminta kunci API yang baru.','Custom'=>'Kustom','Flag to use for this language: '=>'Tandai untuk digunakan untuk bahasa ini: ','Custom flag URL for this language: '=>'URL bendera khusus untuk bahasa ini: ','Important: space out the addition of new languages ​​by at least ten days and browse your site for the first time in the added languages. This promotes better indexing by search engines, reduces the load on your server and minimizes the risk of slowdowns on your site.'=>'Penting: beri jarak waktu minimal sepuluh hari untuk penambahan bahasa baru dan jelajahi situs Anda untuk pertama kalinya dalam bahasa yang ditambahkan. Hal ini mendorong pengindeksan yang lebih baik oleh mesin pencari, mengurangi beban pada server Anda dan meminimalkan risiko perlambatan pada situs Anda.','Add new target Language: '=>'Menambahkan Bahasa target baru: ','Add language'=>'Tambahkan bahasa','(Private)'=>'(Pribadi)','Move up'=>'Bergerak ke atas','Move down'=>'Bergerak ke bawah','Make this language private'=>'Jadikan bahasa ini pribadi','Private languages will only be visible to logged-in users with editing rights. This option allows administrators to pre-generate and correct translations before they are accessible to the public.'=>'Bahasa pribadi hanya akan terlihat oleh pengguna yang masuk dengan hak pengeditan. Opsi ini memungkinkan administrator untuk membuat dan mengoreksi terjemahan sebelum dapat diakses oleh publik.','Target languages enabled: '=>'Bahasa target diaktifkan: ','Access more target languages by upgrading your API key.'=>'Akses lebih banyak bahasa target dengan meningkatkan kunci API Anda.','Available languages: '=>'Bahasa yang tersedia: ','wplingua.com : Upgrade your API key'=>'wplingua.com : Tingkatkan kunci API Anda','API translation features: '=>'Fitur terjemahan API: ','The options below require extended access to the wpLingua API to be functional on your website.'=>'Opsi-opsi di bawah ini memerlukan akses yang diperluas ke API wpLingua agar dapat berfungsi di situs web Anda.','Use of the free wpLingua API keys is reserved for personal blogs and non-profit websites; paid subscriptions are available for companies and commercial websites.'=>'Penggunaan kunci API wpLingua gratis diperuntukkan bagi blog pribadi dan situs web nirlaba; langganan berbayar tersedia untuk perusahaan dan situs web komersial.','Search from translated languages'=>'Cari dari bahasa yang diterjemahkan','Enable visitors to search on your website in their own language.'=>'Memungkinkan pengunjung untuk mencari di situs web Anda dalam bahasa mereka sendiri.','Example: if your website is translated from English to French and you have a post named "Hello". When a French visitor searches for the term "Bonjour" on the website, this feature will translate it on the fly to "Hello" before launching the search. This will allow WordPress to find the post named "Hello" when your visitor has searched for "Bonjour".'=>'Contoh: jika situs web Anda diterjemahkan dari bahasa Inggris ke bahasa Prancis dan Anda memiliki postingan bernama "Halo". Saat pengunjung dari Prancis mencari istilah "Bonjour" di situs web, fitur ini akan menerjemahkannya dengan cepat menjadi "Hello" sebelum meluncurkan pencarian. Hal ini akan memungkinkan WordPress untuk menemukan postingan bernama "Hello" ketika pengunjung Anda mencari "Bonjour".','SEO features: '=>'Fitur SEO: ','Add hreflang tags to translated pages'=>'Menambahkan tag hreflang ke halaman yang diterjemahkan','This option automatically adds hreflang tags to your pages that are available in multiple languages.'=>'Opsi ini secara otomatis menambahkan tag hreflang ke halaman Anda yang tersedia dalam berbagai bahasa.','Hreflang tags are HTML metadata used to indicate the URLs of each language version of a page. They are not visible to visitors, but they allow search engines (Google, Bing, etc.) to identify the multilingual structure of the site and display the correct version according to the user\'s language.'=>'Tag hreflang adalah metadata HTML yang digunakan untuk menunjukkan URL setiap versi bahasa dari sebuah halaman. Tag ini tidak terlihat oleh pengunjung, tetapi memungkinkan mesin pencari (Google, Bing, dll.) untuk mengidentifikasi struktur multibahasa situs dan menampilkan versi yang benar sesuai dengan bahasa pengguna.','Enable multilingual XML Sitemap'=>'Mengaktifkan Peta Situs Web XML multibahasa','This option automatically adds your wpLingua translated pages into your XML Sitemap files.'=>'Opsi ini secara otomatis menambahkan halaman hasil terjemahan wpLingua Anda ke dalam file Sitemap XML.','An XML Sitemap is used by search engines (Google, Bing, etc.) to better discover and index the pages of your website. By default, only the default language pages are included. With this option enabled, all translated versions of your content will also be listed.'=>'Peta Situs XML digunakan oleh mesin pencari (Google, Bing, dll.) untuk menemukan dan mengindeks halaman situs web Anda dengan lebih baik. Secara default, hanya halaman bahasa default yang disertakan. Dengan mengaktifkan opsi ini, semua versi terjemahan konten Anda juga akan dicantumkan.','This greatly improves SEO visibility, ensuring that search engines can easily find and index your content in every language.'=>'Hal ini sangat meningkatkan visibilitas SEO, memastikan bahwa mesin pencari dapat dengan mudah menemukan dan mengindeks konten Anda dalam setiap bahasa.','wpLingua uses a universal method that intercepts and extends sitemap. It works with the native WordPress sitemap and with popular SEO plugins such as Yoast SEO, Rank Math, All in One SEO, SEOPress, etc.'=>'wpLingua menggunakan metode universal yang mencegat dan memperluas peta situs. Metode ini bekerja dengan peta situs WordPress asli dan dengan plugin SEO populer seperti Yoast SEO, Rank Math, All in One SEO, SEOPress, dll.','Use wpLingua display for XML Sitemap'=>'Gunakan tampilan wpLingua untuk Peta Situs XML','This option replaces the default XML Sitemap stylesheet with wpLingua\'s custom display.'=>'Opsi ini mengganti lembar gaya Peta Situs XML bawaan dengan tampilan khusus wpLingua.','When enabled, the XML Sitemap will use a wpLingua-designed stylesheet that visually displays all translated URLs directly under each original URL. This makes it easy to verify that all language versions are correctly included in your sitemap.'=>'Jika diaktifkan, Peta Situs XML akan menggunakan lembar gaya yang dirancang oleh wpLingua untuk menampilkan secara visual semua URL yang telah diterjemahkan tepat di bawah setiap URL asli. Hal ini memudahkan Anda untuk memastikan bahwa semua versi bahasa telah dimasukkan dengan benar ke dalam peta situs Anda.','Note: This only affects how the sitemap is displayed in your browser. The actual XML data sent to search engines remains unchanged and fully compatible with all SEO standards.'=>'Catatan: Hal ini hanya memengaruhi cara peta situs ditampilkan di browser Anda. Data XML yang sebenarnya yang dikirimkan ke mesin pencari tetap tidak berubah dan sepenuhnya sesuai dengan semua standar SEO.','This option has no effect when using All In One SEO, as this plugin handles the display of translated links itself.'=>'Opsi ini tidak berpengaruh saat menggunakan All In One SEO, karena plugin ini sendiri yang mengatur tampilan tautan yang telah diterjemahkan.','More features: '=>'Fitur lainnya: ','Translation progress bar for editors'=>'Bilah kemajuan terjemahan untuk editor','Enable progress bar: Smooth translations loading for editors'=>'Mengaktifkan bilah kemajuan: Pemuatan terjemahan yang lancar untuk editor','Activate a progress bar when a page requires the generation of more than 10 new string translations. This feature only applies to connected editors.'=>'Aktifkan bilah kemajuan jika sebuah halaman memerlukan pembuatan lebih dari 10 terjemahan string baru. Fitur ini hanya berlaku untuk editor yang terhubung.','Enable language browser redirection'=>'Mengaktifkan pengalihan browser bahasa','This option automatically redirects visitors to the translated version of your site that matches their browser language when they land on the main homepage. It can improve user experience by showing content in the right language immediately, but depending on your setup, it may introduce side effects.'=>'Opsi ini secara otomatis mengarahkan pengunjung ke versi terjemahan situs Anda yang sesuai dengan bahasa peramban mereka ketika mereka tiba di halaman beranda utama. Opsi ini dapat meningkatkan pengalaman pengguna dengan menampilkan konten dalam bahasa yang tepat dengan segera, tetapi tergantung pada pengaturan Anda, opsi ini dapat menimbulkan efek samping.','Disabled (recommended):'=>'Dinonaktifkan (disarankan):','No redirection is applied. Every visitor always sees the default homepage, regardless of their browser language. This is the safest option and ensures maximum compatibility with caching systems, SEO, and shared links. Recommended if you are unsure which option to choose.'=>'Tidak ada pengalihan yang diterapkan. Setiap pengunjung selalu melihat beranda default, apa pun bahasa peramban mereka. Ini adalah opsi yang paling aman dan memastikan kompatibilitas maksimum dengan sistem cache, SEO, dan tautan bersama. Direkomendasikan jika Anda tidak yakin opsi mana yang harus dipilih.','JS only:'=>'JS saja:','The redirect is handled with JavaScript, after the default homepage has loaded. This method works in almost all cases and avoids issues with caching plugins. However, it may cause a short flicker effect: users will briefly see the default page before being redirected to the translated version.'=>'Pengalihan ditangani dengan JavaScript, setelah halaman beranda default dimuat. Metode ini bekerja di hampir semua kasus dan menghindari masalah dengan plugin cache. Namun, metode ini dapat menyebabkan efek kedipan singkat: pengguna akan melihat halaman default secara singkat sebelum dialihkan ke versi terjemahan.','PHP and JS:'=>'PHP dan JS:','The redirect is performed server-side with PHP, which makes it faster and more seamless for visitors. In addition, a cookie is set via JavaScript to remember the user’s preferred language for future visits. While this provides the smoothest experience, it can sometimes conflict with caching systems (static pages, CDN, aggressive cache settings) and may cause incorrect redirects in certain setups.'=>'Pengalihan dilakukan di sisi server dengan PHP, yang membuatnya lebih cepat dan lebih mulus bagi pengunjung. Selain itu, cookie dipasang melalui JavaScript untuk mengingat bahasa pilihan pengguna untuk kunjungan berikutnya. Meskipun ini memberikan pengalaman yang paling lancar, terkadang dapat bertentangan dengan sistem cache (halaman statis, CDN, pengaturan cache yang agresif) dan dapat menyebabkan pengalihan yang salah dalam pengaturan tertentu.','Disable (recommended)'=>'Nonaktifkan (disarankan)','Enable with JS only'=>'Aktifkan hanya dengan JS','Enable with PHP and JS'=>'Aktifkan dengan PHP dan JS','Website API key: '=>'Kunci API situs web: ','The API key connects the website to wpLingua\'s online services and automatic translation generators.'=>'Kunci API menghubungkan situs web ke layanan online wpLingua dan generator terjemahan otomatis.','Show API key'=>'Tampilkan kunci API','Hide API key'=>'Sembunyikan kunci API','API key status: '=>'Status kunci API: ','Premium expiration: '=>'Masa berlaku premi berakhir: ','wpLingua - Switcher settings'=>'wpLingua - Pengaturan pengalih','No target language selected.'=>'Tidak ada bahasa target yang dipilih.','Preview'=>'Pratinjau','Design'=>'Desain','Layout: '=>'Tata Letak: ','This option allow you to define the layout of the languages ​​in the switcher.'=>'Opsi ini memungkinkan Anda menentukan tata letak bahasa dalam switcher.','Inline list: '=>'Daftar sebaris: ','the languages ​​are lined up next to each other.'=>'bahasa-bahasa tersebut berbaris bersebelahan.','Block: '=>'Blok: ','the languages ​​are placed in columns, one under the other.'=>'bahasa ditempatkan dalam kolom, satu di bawah yang lain.','Dropdown: '=>'Dropdown: ','the languages ​​appear in a drop-down menu; this is recommended when your website offers several languages.'=>'bahasa muncul dalam menu drop-down; ini direkomendasikan ketika situs web Anda menawarkan beberapa bahasa.','Displayed names: '=>'Nama yang ditampilkan: ','This option allow you to choose how the languages names should be written in the switcher.'=>'Opsi ini memungkinkan Anda untuk memilih bagaimana nama bahasa harus ditulis dalam switcher.','Translated names: '=>'Nama yang diterjemahkan: ','the name of the languages ​​is translated into the current language displayed.'=>'nama bahasa diterjemahkan ke dalam bahasa yang ditampilkan saat ini.','Original name: '=>'Nama asli: ','each language retains its name in its own language (English, Français, 日本語, Português, Español, etc.).'=>'setiap bahasa mempertahankan namanya dalam bahasanya sendiri (Inggris, Prancis, Jepang, Português, Spanyol, dll.).','Language ID: '=>'ID Bahasa: ','language names use language ID (FR, EN, DE, RU, etc.).'=>'nama bahasa menggunakan ID bahasa (FR, EN, DE, RU, dll.).','No display: '=>'Tidak ada tampilan: ','no text, only flags are displayed.'=>'tidak ada teks, hanya bendera yang ditampilkan.','Flags style: '=>'Gaya bendera: ','This option allow you to choose the appearance of the flags in the switcher. '=>'Opsi ini memungkinkan Anda untuk memilih penampilan bendera di switcher. ','Circle: '=>'Lingkaran: ','display round flags.'=>'menampilkan bendera bulat.','Rectangular: '=>'Persegi panjang: ','display rectangular flags.'=>'menampilkan bendera persegi panjang.','Wave: '=>'Gelombang: ','display wavy flags.'=>'menampilkan bendera bergelombang.','no display any flags, only the language name will be displayed.'=>'tidak menampilkan bendera apa pun, hanya nama bahasa yang akan ditampilkan.','You can also change the country flag or set a custom flag from wpLingua ➔ General settings. For example, you can set the flag of Mexico for Spanish instead of the flag of Spain.'=>'Anda juga dapat mengubah bendera negara atau mengatur bendera khusus dari wpLingua ➔ Pengaturan umum. Misalnya, Anda dapat mengatur bendera Meksiko untuk bahasa Spanyol, bukan bendera Spanyol.','Color theme: '=>'Tema warna: ','This option allows you to choose the color and border styles of the languages switcher.'=>'Opsi ini memungkinkan Anda untuk memilih warna dan gaya batas pengalih bahasa.','The color options offer 5 themes: '=>'Pilihan warna menawarkan 5 tema: ','Light: '=>'Cahaya: ','white color in the background of the switcher.'=>'warna putih di latar belakang pengalih.','Grey: '=>'Abu-abu: ','grey background color.'=>'warna latar belakang abu-abu.','Dark: '=>'Gelap: ','black background color.'=>'warna latar belakang hitam.','Blur Black: '=>'Blur Black: ','transparent and blurred background color with black text and borders.'=>'warna latar belakang transparan dan kabur dengan teks dan garis tepi hitam.','Blur White: '=>'Blur White: ','transparent and blurred background color with white text and borders.'=>'warna latar belakang transparan dan kabur dengan teks dan garis tepi putih.','Each theme is then broken down by shape and border style:'=>'Setiap tema kemudian dipecah berdasarkan bentuk dan gaya perbatasan:','Double – Smooth: '=>'Ganda - Halus: ','the switcher will be framed by a double border with rounded corners.'=>'pengalih akan dibingkai oleh batas ganda dengan sudut membulat.','Double – Square: '=>'Ganda - Persegi: ','double border with square corners.'=>'batas ganda dengan sudut persegi.','Simple – Smooth: '=>'Sederhana - Halus: ','single border with rounded corners.'=>'batas tunggal dengan sudut membulat.','Simple – Square: '=>'Sederhana - Persegi: ','single border with square corners.'=>'batas tunggal dengan sudut persegi.','Custom CSS'=>'Kustom CSS','Set custom CSS: '=>'Mengatur CSS khusus: ','The field below allows you to add custom CSS code that will run on all pages.'=>'Kolom di bawah ini memungkinkan Anda untuk menambahkan kode CSS khusus yang akan berjalan di semua halaman.','First of all, note that the CSS class <code>.switcher-content</code> allows you to act on the entire block of the language switcher while the class <code>.wplng-langague</code> allows you to act on the languages ​​themselves.'=>'Pertama-tama, perhatikan bahwa kelas CSS <code>.switcher-content</code> memungkinkan Anda untuk bertindak pada seluruh blok pengalih bahasa sementara kelas <code>.wplng-langague</code> memungkinkan Anda untuk bertindak pada bahasa itu sendiri.','To change the background and border colors of languages, here is the CSS:'=>'Untuk mengubah latar belakang dan warna batas bahasa, berikut ini adalah CSS-nya:','More example on wplingua.com'=>'Lebih banyak contoh di wplingua.com','Insertion'=>'Penyisipan','Automatic insert: '=>'Penyisipan otomatis: ','Choose a predefined location: '=>'Pilih lokasi yang telah ditentukan sebelumnya: ','Bottom right: '=>'Kanan bawah: ','the switcher is placed at the bottom right of the screen.'=>'pengalih ditempatkan di kanan bawah layar.','Bottom Center: '=>'Pusat bawah: ','bottom center of the screen.'=>'tengah bawah layar.','Bottom left: '=>'Kiri bawah: ','bottom left of the screen.'=>'kiri bawah layar.','None: '=>'Tidak ada: ','the switcher is not inserted automatically.'=>'pengalih tidak dimasukkan secara otomatis.','Shortcode switcher: '=>'Pengalih kode pendek: ','If you want to insert the language switcher only in certain places on your website, you can use the shortcode provided for this purpose. Note that in this case, the previous option should be "None". This method is ideal for placing the switcher where you want it, whether you are using a Gutenberg block-based theme (FSE), a classic theme or even a page or theme builder like Divi, Elementor...'=>'Jika Anda ingin menyisipkan pengalih bahasa hanya di tempat-tempat tertentu di situs web Anda, Anda dapat menggunakan kode pendek yang disediakan untuk tujuan ini. Perhatikan bahwa dalam kasus ini, opsi sebelumnya harus "Tidak Ada". Metode ini sangat ideal untuk menempatkan pengalih bahasa di tempat yang Anda inginkan, baik Anda menggunakan tema berbasis blok Gutenberg (FSE), tema klasik, atau bahkan pembangun halaman atau tema seperti Divi, Elementor...','Gutenberg & FSE: '=>'Gutenberg & FSE: ','Block wpLingua Switcher'=>'Blokir wpLingua Switcher','Block based themes, wpLingua offers a dedicated Gutenberg block. You can insert the switcher wherever you want, whether in the content or via the overall site editor.'=>'Tema berbasis blok, wpLingua menawarkan blok Gutenberg khusus. Anda dapat menyisipkan pengalih di mana pun Anda inginkan, baik di dalam konten atau melalui editor situs secara keseluruhan.','Switcher in menu: '=>'Pengalih dalam menu: ','Appearance ➔ Menus'=>'Penampilan ➔ Menu','If the active theme manages menus (classic theme), it is possible to add a language switcher. The design of these language switchers will be defined by the theme. Go to the Appearance ➔ Menu tab to add the wpLingua switcher as a menu item. It is also possible to add it as a sub-element.'=>'Jika tema yang aktif mengelola menu (tema klasik), dimungkinkan untuk menambahkan pengalih bahasa. Desain pengalih bahasa ini akan ditentukan oleh tema. Buka tab Penampilan ➔ Menu untuk menambahkan pengalih wpLingua sebagai item menu. Anda juga dapat menambahkannya sebagai sub-elemen.','wpLingua: Register'=>'wpLingua: Daftar','wpLingua: Settings'=>'wpLingua: Pengaturan','General settings'=>'Pengaturan Umum','wpLingua: Switcher'=>'wpLingua: Pengalih','Switcher'=>'Pengalih','wpLingua: Exclusion'=>'wpLingua: Pengecualian','Exclusion'=>'Pengecualian','wpLingua: Dictionary'=>'wpLingua: Kamus','Dictionary'=>'Kamus','wplingua: Links & Medias'=>'wplingua: Tautan & Media','Links & Medias'=>'Tautan & Media','wpLingua: Website slugs'=>'wpLingua: Siput situs web','Website slugs'=>'Siput situs web','wpLingua: Translations'=>'wpLingua: Terjemahan','All translations'=>'Semua terjemahan','Thank you for choosing wpLingua!'=>'Terima kasih telah memilih wpLingua!','If you like wpLingua please leave us a %1$s rating. A huge thanks!'=>'Jika Anda menyukai wpLingua, silakan beri kami peringkat %1$s. Terima kasih banyak!','five stars'=>'lima bintang','Version'=>'Versi','Settings'=>'Pengaturan','wpLingua - Translation solution for multilingual website'=>'wpLingua - Solusi penerjemahan untuk situs web multibahasa','wpLingua is installed, but not yet configured. You are just a few clicks away from making your website multilingual!'=>'wpLingua telah terinstal, tetapi belum dikonfigurasi. Anda hanya perlu beberapa klik saja untuk membuat situs web Anda menjadi multibahasa!','Go to the configuration page'=>'Buka halaman konfigurasi','wpLingua - Incompatible plugin detected'=>'wpLingua - Plugin yang tidak kompatibel terdeteksi','You have several translation plugins. This may result in unpredictable or incorrect behavior. For best results, use only one translation plugin at a time. These plugins can cause problems with wpLingua: '=>'Anda memiliki beberapa pengaya terjemahan. Hal ini dapat mengakibatkan perilaku yang tidak terduga atau salah. Untuk hasil terbaik, gunakan hanya satu plugin terjemahan dalam satu waktu. Plugin ini dapat menyebabkan masalah pada wpLingua: ','Deactivate plugin: %1$s'=>'Menonaktifkan plugin: %1$s','Deactivate'=>'Nonaktifkan','Manage active plugins'=>'Mengelola plugin yang aktif','wpLingua - Incompatible with multisite'=>'wpLingua - Tidak kompatibel dengan multisite','wpLingua is not compatible with multisite.'=>'wpLingua tidak kompatibel dengan multisite.','wpLingua - Incompatible with WordPress installed in a subfolder'=>'wpLingua - Tidak kompatibel dengan WordPress yang diinstal dalam subfolder','wpLingua is not compatible with WordPress installed in a subfolder.'=>'wpLingua tidak kompatibel dengan WordPress yang diinstal dalam subfolder.','wpLingua - Incompatible PHP version'=>'wpLingua - Versi PHP yang tidak kompatibel','wpLingua is not compatible with your PHP version. wpLingua requires PHP 7.4 or higher.'=>'wpLingua tidak kompatibel dengan versi PHP Anda. wpLingua membutuhkan PHP 7.4 atau lebih tinggi.','wpLingua - Incompatible HTACCESS file'=>'wpLingua - File HTACCESS yang tidak kompatibel','It seems that a plugin was incorrectly deactivated and corrupted the site\'s HTACCESS file, preventing the correct redirection of translated pages. Please edit the ".htaccess" file located at the root of the site and delete the lines between :'=>'Tampaknya sebuah plugin telah dinonaktifkan dengan tidak benar dan merusak file HTACCESS situs, sehingga mencegah pengalihan yang benar dari halaman yang diterjemahkan. Harap edit file ".htaccess" yang terletak di root situs dan hapus baris di antara file :','wpLingua - Website slugs'=>'wpLingua - Slug situs web','wpLingua - Website slug'=>'wpLingua - Slug situs web','wpLingua - All slugs'=>'wpLingua - Semua slug','wpLingua - Edit slug'=>'wpLingua - Edit slug','Search slugs'=>'Cari slug','All slug status'=>'Semua status siput','Reviewed'=>'Telah Diperiksa','Unreviewed'=>'Belum ditinjau','Full reviewed'=>'Ulasan lengkap','Partially reviewed'=>'Ditinjau sebagian','Full unreviewed'=>'Penuh belum ditinjau','Slug status'=>'Status slug','Slug status: '=>'Status slug: ','Slug'=>'Slug','Flag for language: '=>'Tandai untuk bahasa: ',' - Original slug: '=>' - Slug asli: ','Regenerate translation'=>'Membuat ulang terjemahan','Mark as review'=>'Tandai sebagai ulasan','Generate translation'=>'Menghasilkan terjemahan','Reviewed on '=>'Ditinjau pada ',' - Slug translation: '=>' - Terjemahan siput: ','Is reviewed'=>'Ditinjau','Invalid parameters'=>'Parameter tidak valid','Invalid languages parameters'=>'Parameter bahasa tidak valid','Invalid API response'=>'Respons API tidak valid','These options are used to add a language switcher in a menu. This language switcher automatically uses the menu design.'=>'Opsi ini digunakan untuk menambahkan pengalih bahasa dalam menu. Pengalih bahasa ini secara otomatis menggunakan desain menu.','Displayed flag: '=>'Bendera yang ditampilkan: ','Language switcher'=>'Pengalih bahasa','Add to menu'=>'Tambahkan ke menu','wpLingua - Translations'=>'wpLingua - Terjemahan','wpLingua - Translation'=>'wpLingua - Terjemahan','wpLingua - All translations'=>'wpLingua - Semua terjemahan','wpLingua - Edit translation'=>'wpLingua - Edit terjemahan','Search translations'=>'Cari terjemahan','All translation status'=>'Semua status terjemahan','Translation status'=>'Status terjemahan','Translation status: '=>'Status terjemahan: ','All languages'=>'Semua Bahasa','Open edit page'=>'Buka halaman edit','Edit translation'=>'Edit terjemahan','Invalid translation ID'=>'ID terjemahan tidak valid','Invalid translation post'=>'Pos terjemahan tidak valid','Translation saving failed'=>'Penyimpanan terjemahan gagal','Translation'=>'Terjemahan',' - Original text: '=>' - Teks asli: ',' - Translation: '=>' - Terjemahan: ','Discovery URL: '=>'URL Penemuan: ','Error - Invalid data.'=>'Kesalahan - Data tidak valid.','Error - Invalid data (email address).'=>'Kesalahan - Data (alamat email) tidak valid.','Error - Invalid data (website URL).'=>'Kesalahan - Data tidak valid (URL situs web).','Error - Invalid data (languages).'=>'Kesalahan - Data (bahasa) tidak valid.','Error - The API could not be called.'=>'Kesalahan - API tidak dapat dipanggil.','Error - API response not valid.'=>'Kesalahan - Respons API tidak valid.','Code'=>'Kode','API returned an unexpected response.'=>'API mengembalikan respons yang tidak diharapkan.','You are about to exit without saving your changes. They will be lost if you continue. Would you like to leave anyway?'=>'Anda akan keluar tanpa menyimpan perubahan Anda. Perubahan tersebut akan hilang jika Anda melanjutkan. Apakah Anda tetap ingin keluar?','Save in progress...'=>'Menyimpan dalam proses...','Translation API overloaded'=>'API terjemahan kelebihan beban','Translation API overloaded. Retry in a few minutes or '=>'API Terjemahan overload. Coba lagi dalam beberapa menit atau ','upgrade your API key'=>'perbarui kunci API Anda',' to get priority API access.'=>' untuk mendapatkan akses prioritas ke API.','Translation API overloaded. Please retry in a few minutes.'=>'API Terjemahan sedang sibuk. Silakan coba lagi dalam beberapa menit.','Close'=>'Tutup','Translation in progress'=>'Penerjemahan sedang berlangsung','In progress: Translation and saving of new texts'=>'Sedang berlangsung: Penerjemahan dan penyimpanan teks baru','Error during translation.'=>'Terjadi kesalahan saat penerjemahan.','Error during translation. Check the browser console for more information.'=>'Terjadi kesalahan saat menerjemahkan. Periksa konsol browser untuk informasi lebih lanjut.','Edit this translation'=>'Edit terjemahan ini','Search'=>'Cari','Status'=>'Status','All'=>'Semua','Order'=>'Pesanan','Occurrence order'=>'Urutan kejadian','Alphabetical - sources'=>'Menurut abjad - sumber','Alphabetical - translations'=>'Abjad - terjemahan','SEO - Title:'=>'SEO - Judul:','SEO - Description:'=>'SEO - Deskripsi:','Go to top'=>'Pergi ke atas','...'=>'...','language'=>'bahasa','switcher'=>'pengalih','multilanguage'=>'multibahasa','multilingual'=>'multibahasa','translate'=>'menerjemahkan','translation'=>'terjemahan','flag'=>'bendera','flags'=>'bendera','wpLingua: languages switcher'=>'wpLingua: pengalih bahasa','Add a language switcher to your page.'=>'Tambahkan pengalih bahasa ke halaman Anda.','Languages switcher'=>'Pengalih bahasa','Display the wpLingua languages switcher.'=>'Menampilkan pengalih bahasa wpLingua.','Default'=>'Default','https://wplingua.com/'=>'https://wplingua.com/','An all-in-one solution that makes your websites multilingual and translates them automatically, without word or page limits. The highlights: a free first language, an on-page visual editor for editing translations, a customizable language switcher, search engine optimization (SEO), self-hosted data and more!'=>'Solusi lengkap yang menjadikan situs web Anda multibahasa dan menerjemahkannya secara otomatis, tanpa batas kata atau halaman. Fitur-fitur utama: bahasa pertama gratis, editor visual di halaman untuk mengedit terjemahan, pengalih bahasa yang dapat disesuaikan, pengoptimalan mesin pencari (SEO), data yang dihosting sendiri, dan masih banyak lagi!','wpLingua Translation Service'=>'layanan Terjemahan wpLingua']];
